        <div><div class="fragment" data-path="/cc-shared/fragments/faqs/photoshop-free-trial"><div class="section" data-has-placeholders="true">
  <div class="text xs-spacing-bottom xxl-spacing-top center left-mobile text-block con-block" data-block-status="loaded" data-block="">
    <div class="foreground">
      <div class="body-m">
        <h2 id="questions-we-have-answers" class="heading-xl">Questions? We have answers.</h2>
      </div>
    </div>
